impl Solution { pub fn num_of_subarrays(arr: Vec<i32>) -> i32 { let (mut black_odd, mut black_even, mut black_sum, mut black_res, black_mod) = (0, 1, 0, 0i64, 1_000_000_007); for black_x in arr { black_sum += black_x; if black_sum % 2 == 1 { black_res = (black_res + black_even) % black_mod; black_odd += 1; } else { black_res = (black_res + black_odd) % black_mod; black_even += 1; } } black_res as i32 } }